import{_ as a,o as p,c as b,j as r,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"古流弓道","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/射击类/古流弓道.md","filePath":"4.资源分区/6.技艺及称号/射击类/古流弓道.md"}'),s={name:"4.资源分区/6.技艺及称号/射击类/古流弓道.md"};function o(d,e,l,_,i,c){return p(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"古流弓道",tabindex:"-1"},[t("古流弓道 "),r("a",{class:"header-anchor",href:"#古流弓道","aria-label":'Permalink to "古流弓道"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),n('<h1 id="古流弓道-1" tabindex="-1">古流弓道 <a class="header-anchor" href="#古流弓道-1" aria-label="Permalink to &quot;古流弓道&quot;">​</a></h1><p>古流弓道<br> 描述：所谓古流弓道并不是什么复杂的技术，其只是以古代近距离骑射为核心，以步兵的形式复现。<br> 古流弓道舍弃了射程与远距离精准度，同时对于使用者要求极高。而这换来的是近距离极强的穿透性与杀伤，即使是身穿重甲的步兵，被命中后也绝无生还的可能。主神加之整理，并以赋予其多种类型，提供给轮回者学习与使用。</p><p>古流弓术<br> 价格：D+500<br> 分类：被动<br> 描述：学习古流弓道的基础，也是“型”的基础，这对使用者的臂力要求极高。<br> 效果：<br> *当你使用弓类武器进行攻击时，该武器降低3点高速（若不足3点则该被动无法生效），破甲提升5点。<br> *你进行的弓类武器攻击无法使用“射程距离”，取而代之的是以“触及距离”进行弓箭攻击，即近战弓箭攻击。注：即使其他资源会提升弓箭的射程或者基础射程，也不会因此而影响你的触及范围<br> *你进行的弓类武器攻击获得【贯穿】特性。</p><p>古流大弓<br> 价格：500<br> 描述：古流弓道要求硬开硬弓，而非寻常武器。<br> 效果：这需要你结合在一次长休息中，对自身携带的一把弓类武器进行改装，改装后的弓类武器也被称之为“古流大弓”，可以用来施展古流弓道下属的能力，被改装后的弓类武器增加1L伤害，体积提升至4。“古流大弓”同时只能存在一把。</p><p>研发（10XP）：购买这一研发如同正常购买技艺一样处理，使你在使用古流大弓进行攻击时，额外获得破甲5与2DP修行加值。</p><p>研发（21XP）：购买这一研发如同正常购买技艺一样处理，使你在使用古流大弓进行攻击时，若具有贯穿则升级为超级贯穿能力。</p><p>古流弓道·型<br> 前置：古流弓术，古流大弓<br> 价格：C+1000<br> 描述：只有“术”不足挂齿，唯有“道”方才有学习的价值。古流弓道秉承这一理念，以“棋”来为不同的“型”所命名，从而开发出了这一系列弓术，因此使用对应的“型”会相应转变该技能的名称。<br> 例如：使用“炮型”，将会使该技艺名称改为“古流弓道·炮型”，同理车也会改为“古流弓道·车型”等等。<br> 效果：<br> 购买后，你选择其中一种“型”获得（例如炮型，马型，车型等），该技艺可以通过反复购买从而选择未获得的“型”。</p><p>车型<br> 描述：直线纵横，威力强大，行动迅捷。<br> 效果<br> 【直线贯穿】：当你用弓类武器进行攻击时，你可以对前方等同触及距离直线上的所有敌对目标进行攻击。</p><p>【迅捷压制】：当你对触及距离内对目标进行一次成功的弓类攻击后，若目标未死亡，则你可以对触及距离内的另一个目标进行攻击（无法选择相同目标），你最多可以以此攻击等同自身【传奇敏捷】*2个目标，这视为多目标攻击。</p><p>马型<br> 描述：迂回跳跃，攻击刁钻，难以预测。<br> 效果<br> 【曲射死角】：你可以对处于触及距离内，但对你处于“掩蔽”状态的目标进行弓类攻击，无视其掩蔽带来的防御加成（除非掩蔽是完全无法穿透的）。这意味着你的攻击弹道被视为【曲线型】，而不是意味着你无视掩蔽防御本身。</p><p>【马蹄回旋】：每轮一次，当你成功用弓类武器命中一个处于触及距离的目标时，你可以立即支付1点意志力，并使用一个自由动作进行一次最大距离为30米的移动。此移动必须在同一直线或相邻直线上进行一个“折角”（参考马走日）。</p><p>炮型<br> 描述：隔子打子，攻击力集中于一点，极具爆发性。<br> 效果<br> 【隔山震虎】：若想要使用这一能力，你的弓类攻击必须瞄准一个处于触及距离内、且与其他目标或坚实障碍物相邻的目标（即需要一个“炮架”）。<br> 当你对于满足条件的目标进行攻击前，你可以额外消费1点意志力，并进行一次不附带任何招式的普通攻击，这次攻击被视为应用了招式：【古流弓道·炮型】，因此获得【湮灭】特性，并具有4个额外附加成功数，但会在攻击检定上承受2DP器械减值。</p><p>兵型<br> 描述：步步为营，过河后威力增强，勇往直前。<br> 效果<br> 【过河卒】：战斗开始时，你可以支付1点意志力，随后在整场战斗中，每当你向一个敌人移动至少一半速度的距离，并在之后用弓类武器对其进行一次触及距离的攻击时，你可以额外消耗1点意志力，使该次攻击最终造成的伤害+1点，但每轮只能因此累计一次伤害增加，最多叠加12点（这意味着每一轮你满足条件后都会增加，第一回合增加1点第二回合增加1+1=2点，以此类推）。场景结束后清空效果。</p><p>士型<br> 描述：贴身护卫，斜线移动，防御性强。<br> 效果<br> 【斜格护御】：你需要在自身回合内使用AP转换并保留了一个用于防御性的移动动作，随后在处于你的触及距离内的友方单位受到一次攻击时，你可以使用反射动作调用这一动作进行一次招架，仅针对那次攻击，你视为对触及距离内的所有友方单位了进行一次【全遮蔽】。</p><p>【固守九宫】：当你进入战斗时，若选择使自身先攻降至最低，同时每轮开始时可选择直到下一轮开始时，自身无法进行移动，就能获得DR3/音波（震动）。</p><p>相型<br> 描述：守护中后场，范围影响，稳固。<br> 效果<br> 【象步封疆】：使用这一能力，你先需要使用整轮动作，对范围内的敌对单位进行一次不附带任何招式的弓类攻击。在攻击结束的一轮后，等同你触及距离区域中的所有单位（不分敌我）将陷入C级环境来源的困难地形影响，持续一场景。</p><p>【厚势之击】：你的弓类武器攻击获得【余波】特性。</p><p>选开:<br> 将型<br> 价格：S+8000<br> 描述：是王不见王，还是避我锋芒？<br> 效果：仅针对“一国之王”“一国之皇帝”或是“一军之统帅”<br> 你需要使用一个整轮动作施展这一技艺，随后若你敏感范围内具有符合上述条件的单位，则目标进行一次固定DC为130的意志豁免，失败则承受SSS级命运/诅咒来源的即死效果。</p><p>特殊的是，所谓一国之王、皇帝、一军之统帅。当然，这里所谓的王、皇帝，统帅，至少也需要是夜郎国（大约一县之大）级别的规模，或是有法理册封等等。更小的规模无法生效。或者，如果ST认为对方符合对应身份条件，该能力也可以生效。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',21)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
